-- Seed Tabadul country_of_origin rows from Naqel's Tabadul CountryCode reference sheet.
--
-- Source: /Users/asma/Desktop/Customs AI/other/naqel-shared-data/Naqel
--         (Fields details + Mapping data).xlsx — sheet 'Tabadul CountryCode'.
--
-- Layout: source_value = ISO alpha-2 (INTLCODE column, e.g. 'CN', 'US', 'GB')
--         canonical_value = Tabadul numeric CountryCode (e.g. '142' for China)
--         metadata = { name_en, name_ar }
--
-- 307 rows. Same idempotent ON CONFLICT pattern as the currency seed (PR E).
--
-- This unblocks Phase 2 declaration rendering, which was failing on every
-- row whose country_of_origin wasn't yet seeded — most batches today fail
-- at this lookup step before XML can be written.

ON CONFLICT ON CONSTRAINT tabadul_codes_natural_uniq DO NOTHING;
